// Normalize data dari Workflow 1
const body = $input.first().json;
let extracted = body.extracted;

// Kalau extracted dikirim sebagai string (JSON.stringify), parse dulu
if (typeof extracted === 'string') {
  try { extracted = JSON.parse(extracted); } catch(e) { extracted = {}; }
}

// Map building_type ke id spreadsheet
const typeMap = {
  'rumah': { type: 'Rumah Tinggal', defaultTier: 'Standar' },
  'cafe': { type: 'Cafe / Restoran', defaultTier: 'Standar' },
  'restoran': { type: 'Cafe / Restoran', defaultTier: 'Standar' },
  'kantor': { type: 'Kantor', defaultTier: 'Standar' },
  'villa': { type: 'Villa / Guest House', defaultTier: 'Standar' },
  'guest house': { type: 'Villa / Guest House', defaultTier: 'Standar' },
  'ruko': { type: 'Ruko / Kios', defaultTier: 'Standar' },
  'kios': { type: 'Ruko / Kios', defaultTier: 'Standar' },
  'renovasi': { type: 'Renovasi (Parsial)', defaultTier: 'Sedang' },
};

// Map tier dari AI ke tier spreadsheet
const tierMap = {
  'ekonomi': 'Ekonomi',
  'standar': 'Standar',
  'menengah': 'Menengah Atas',
  'premium': 'Premium',
  'mewah': 'Mewah/Premium',
  'ringan': 'Ringan',
  'sedang': 'Sedang',
  'full gut': 'Full Gut',
};

// Map service_type ke kategori spreadsheet
const serviceMap = {
  'arsitektur': 'Arsitektur',
  'interior': 'Interior',
  'komersial': 'Komersial',
  'lansekap': 'Lansekap',
  'pengawasan': 'Pengawasan',
};

// Auto-detect service dari building type kalau tidak disebutkan
const autoServiceMap = {
  'cafe': 'Komersial',
  'restoran': 'Komersial',
  'renovasi': 'Interior',
  'villa': 'Arsitektur',
  'rumah': 'Arsitektur',
  'kantor': 'Arsitektur',
  'ruko': 'Arsitektur',
};

const rawType = (extracted.building_type || '').toLowerCase();
const rawTier = (extracted.tier || '').toLowerCase();
const rawService = (extracted.service_type || '').toLowerCase();

const typeInfo = typeMap[rawType] || { type: 'Rumah Tinggal', defaultTier: 'Standar' };
const normalizedTier = tierMap[rawTier] || typeInfo.defaultTier;
const normalizedService = serviceMap[rawService] || autoServiceMap[rawType] || 'Arsitektur';

return [{
  json: {
    from: body.from,
    clientName: body.clientName || 'kak',
    phoneNumberId: body.phoneNumberId,
    buildingType: typeInfo.type,
    tier: normalizedTier,
    areaSqm: extracted.area_sqm || null,
    serviceCategory: normalizedService,
    rawExtracted: extracted
  }
}];

// Ambil data dari kedua sheet dan hitung estimasi
const inputData = $('Normalize Extracted Data').first().json;
const rabRows = $('Sheets — Read RAB Konstruksi').all().map(i => i.json);
const feeRows = $('Sheets — Read Fee Jasa').all().map(i => i.json);

const { buildingType, tier, areaSqm, serviceCategory } = inputData;

// --- STEP 1: Cari baris RAB yang cocok ---
// Coba exact match dulu
let rabRow = rabRows.find(r => {
  const rowType = (r['Tipe Bangunan'] || r['tipe'] || Object.values(r)[0] || '').toString().trim();
  const rowTier = (r['Kelas'] || r['kelas'] || Object.values(r)[1] || '').toString().trim();
  return rowType.toLowerCase().includes(buildingType.toLowerCase().split('/')[0].trim().toLowerCase())
    && rowTier.toLowerCase().includes(tier.toLowerCase().split('/')[0].trim().toLowerCase());
});

// Fallback: cari hanya berdasarkan tipe
if (!rabRow) {
  rabRow = rabRows.find(r => {
    const rowType = (Object.values(r)[0] || '').toString().trim();
    return rowType.toLowerCase().includes(buildingType.toLowerCase().split('/')[0].trim().toLowerCase());
  });
}

// Ultimate fallback: pakai Rumah Tinggal Standar
if (!rabRow) {
  rabRow = rabRows[1] || rabRows[0];
}

// --- STEP 2: Extract harga RAB ---
// Coba berbagai kemungkinan nama kolom
const rabMinRaw = rabRow['Harga Min/m²'] || rabRow['Min'] || rabRow['harga_min'] || Object.values(rabRow)[2] || 0;
const rabMaxRaw = rabRow['Harga Maks/m²'] || rabRow['Maks'] || rabRow['harga_max'] || Object.values(rabRow)[3] || 0;

// Bersihkan nilai (hapus titik, koma, Rp)
const cleanNum = (val) => {
  if (typeof val === 'number') return val;
  return parseFloat(String(val).replace(/[^0-9.]/g, '')) || 0;
};

const rabPriceMin = cleanNum(rabMinRaw);
const rabPriceMax = cleanNum(rabMaxRaw);
const area = areaSqm || 100; // default 100m2 kalau tidak disebutkan

const rabMin = rabPriceMin * area;
const rabMax = rabPriceMax * area;
const rabAvg = (rabMin + rabMax) / 2;

// --- STEP 3: Cari baris Fee yang cocok ---
let feeRow = feeRows.find(r => {
  const rowCat = (r['Kategori'] || r['Jenis Jasa'] || Object.values(r)[0] || '').toString();
  return rowCat.toLowerCase().includes(serviceCategory.toLowerCase().split('/')[0].trim().toLowerCase())
    || rowCat.toLowerCase().includes(serviceCategory.toLowerCase());
});

if (!feeRow) {
  feeRow = feeRows[0]; // fallback ke baris pertama
}

// --- STEP 4: Hitung fee ---
const feePctRaw = feeRow['Fee (%)'] || feeRow['Persentase'] || feeRow['%'] || Object.values(feeRow)[2] || 7;
const feePctStr = String(feePctRaw);

// Handle range "7-10%"
let feePctMin, feePctMax;
if (feePctStr.includes('-')) {
  const parts = feePctStr.replace('%','').split('-');
  feePctMin = parseFloat(parts[0]) || 7;
  feePctMax = parseFloat(parts[1]) || 10;
} else {
  feePctMin = feePctMax = parseFloat(feePctStr.replace('%','')) || 7;
}

const feeMin = rabAvg * feePctMin / 100;
const feeMax = rabAvg * feePctMax / 100;
const feeAvg = (feeMin + feeMax) / 2;

const ppnRate = 0.11;
const ppn = feeAvg * ppnRate;
const totalFee = feeAvg + ppn;

// --- STEP 5: Format angka ke Rupiah ---
const fmt = (n) => {
  if (n >= 1_000_000_000) return `Rp ${(n/1_000_000_000).toFixed(1)} M`;
  if (n >= 1_000_000) return `Rp ${Math.round(n/1_000_000)} jt`;
  return `Rp ${n.toLocaleString('id-ID')}`;
};

const serviceName = feeRow['Jenis Jasa'] || feeRow['Layanan'] || Object.values(feeRow)[0] || 'Jasa Desain';
const spec = rabRow['Spesifikasi'] || rabRow['Keterangan'] || Object.values(rabRow)[4] || '';

return [{
  json: {
    ...inputData,
    area,
    result: {
      buildingType,
      tier,
      areaSqm: area,
      spec,
      rabMin, rabMax, rabAvg,
      rabMinFmt: fmt(rabMin), rabMaxFmt: fmt(rabMax), rabAvgFmt: fmt(rabAvg),
      serviceName,
      serviceCategory,
      feePctMin, feePctMax,
      feeMin, feeMax, feeAvg,
      feeMinFmt: fmt(feeMin), feeMaxFmt: fmt(feeMax), feeAvgFmt: fmt(feeAvg),
      ppn, ppnFmt: fmt(ppn),
      totalFee, totalFeeFmt: fmt(totalFee),
      areaAssumed: !areaSqm
    }
  }
}];

// Build pesan WA yang akan dikirim ke client
const { result, clientName } = $json;
const name = (clientName || 'kak').split(' ')[0];
const r = result;

// Baris asumsi kalau luas tidak disebutkan
const areaNote = r.areaAssumed
  ? `\n(estimasi berdasarkan luas 100m2, sesuaikan kalau beda ya)`
  : '';

// Range fee atau single value
const feeRange = r.feePctMin !== r.feePctMax
  ? `${r.feePctMin}-${r.feePctMax}%`
  : `${r.feePctMin}%`;

const feeDisplay = r.feePctMin !== r.feePctMax
  ? `${r.feeMinFmt} - ${r.feeMaxFmt}`
  : r.feeAvgFmt;

const replyText =
`Halo ${name}, ini estimasi kasarnya ya.

Proyek: ${r.buildingType} ${r.tier}
Luas: ${r.areaSqm}m2${areaNote}
Spesifikasi: ${r.spec || '-'}

Estimasi RAB Konstruksi:
${r.rabMinFmt} - ${r.rabMaxFmt}
(rata-rata ${r.rabAvgFmt})

Fee Jasa Desain Sudut Ruang (${feeRange} dari RAB):
${feeDisplay}

PPN 11%: ${r.ppnFmt}
Total Fee Jasa: ${r.totalFeeFmt}

Ini masih estimasi awal ya, bisa berubah setelah survey dan diskusi detail.

Mau kita buatkan proposal lengkap dengan breakdown lebih rinci?`;

return [{ json: { ...$json, replyText } }];
